class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

class BST:
    def __init__(self):
        self.root = None

    def insert(self, value):
        if self.root is None:
            self.root = Node(value)
        else:
            self._insert_recursive(self.root, value)

    def _insert_recursive(self, node, value):
        if value < node.value:
            if node.left is None:
                node.left = Node(value)
            else:
                self._insert_recursive(node.left, value)
        elif value > node.value:
            if node.right is None:
                node.right = Node(value)
            else:
                self._insert_recursive(node.right, value)

def process_sequence(sequence, index=0, seen=set(), bst=None):
    if bst is None:
        bst = BST()

    if index >= len(sequence):
        return bst

    char = sequence[index].lower()
    if char not in seen:
        seen.add(char)
        bst.insert(char)

    return process_sequence(sequence, index + 1, seen, bst)

# Example usage
alphanumeric_seq = "aB1c2D3e4F"
result_tree = process_sequence(alphanumeric_seq)
